function ConvertTime(e,n){const t=ETOffset+(new Date).getTimezoneOffset()/60,o=n.split(/:| /).map(((e,n)=>n<2?parseInt(e):e)),s=o.pop();o[0]="PM"===s&&12!==o[0]?o[0]+12:"AM"===s&&12===o[0]?0:o[0];const a=e.split("-").map((e=>parseInt(e)));a[1]-=1;const l=new Date(...[...a,...o,0]);return l.setHours(l.getHours()-t),l.toLocaleTimeString().replace(":00","")+" (local time)"}function DisplayLocalTime(e,n){const t=n.innerHTML;return function(o){n.innerHTML=o?t:ConvertTime(e,t)}}function ThisDaysSchedule(e,n){return n.sort(((e,n)=>e.name>n.name?1:e.name<n.name?-1:0)).filter((e=>!e.name.includes("Churchill"))).map((n=>`\n      <tr>\n        <td>${n.canceled?"<s>":""}${n.name}${n.canceled?"</s>":""}</td>\n        <td onMouseOver="localTime=DisplayLocalTime('${e}', this); \n          localTime(false);"\n          onMouseOut="localTime(true);"\n          >${n.posttime}</td>\n      </tr>`))}function FutureSchedules(e){e.forEach((e=>{const n=e.replace("-","/").replace("-","");$.getJSON({url:`https://json.offtrackbetting.com/schedule/${n}.json`,crossDomain:!0,success:n=>$(`#day-${e} tbody`).html(ThisDaysSchedule(e,n)),error:e=>{console.log("fail"),console.log(e)}})}))}function TodaysSchedule(e,n){return n.todaysraces.tracks.map((n=>`\n    <tr>\n      <td><a href="${n.resultsUrl}">${n.name}</a></td>\n      <td onMouseOver="localTime=DisplayLocalTime('${e}', this); \n      localTime(false);" onMouseOut="localTime(true);">${n.time}</td>\n    </tr>`)).join("\n")}